SELECT a.id, a.p_id AS commodityId, a.p_name, a.p_price, a.num, a.size, a.deliver_time, a.sid, a.r_status, a.re_type, a.r_type, a.freight, a.unit, a.user_id, a.r_sNo, a.express_id, a.courier_num, a.coupon_id detailCouponId, a.mch_store_write_id, a.write_time, a.write_time_id, a.platform_coupon_price, a.store_coupon_price, goods.id goodsId, goods.imgurl goodsUrl, goods.is_distribution, goods.write_off_settings, goods.is_appointment, goods.commodity_type, goods.write_off_mch_ids, goods.mch_id, m.img, m.id as attr_id, goods.product_title product_title, m.live_price, goods.gongyingshang gys FROM lkt_order_details AS a LEFT JOIN lkt_configure AS m ON a.sid = m.id left join lkt_product_list goods on goods.id = m.pid
WHERE a.store_id = #{store_id}
#{status,jdbcType=INTEGER}
AND a.id = #{oderDetailId} AND a.r_sNo = #{orderno} AND goods.mch_id = #{mch_id} AND a.recycle = #{recycle} LIMIT #{page},#{pageSize}

select count(1)
from lkt_order_details
where store_id = #{store_id}

    and r_sNo like CONCAT('%',#{orderno},'%')


    and r_status != #{notStatus}

mapper.update:
update lkt_order_details
r_status=#{r_status},
write_off_num=#{write_off_num},
after_write_off_num=#{after_write_off_num},
mch_store_write_id=#{mch_store_write_id},
express_id=#{express_id},
courier_num=#{courier_num},
deliver_time=#{deliver_time},
recycle = #{recycle},
after_discount = #{afterDiscount},
arrive_time = #{arrive_time},
freight = #{upFreight}, after_discount = #{upAfterDiscount},
and id=by_id
and r_sNo = #{orderno}
and id in (${ids})
and r_status = #{rstatus}
and id = #{detailId}
and store_id = #{storeId}
and p_id = #{p_id}
#{id,jdbcType=INTEGER}

mapper.select:
select ifnull(sum(a.num),0) num from lkt_order_details a LEFT JOIN lkt_order b on a.r_sNo=b.sNo LEFT JOIN lkt_product_list
p
on a.p_id=p.id

    b.status in(1,2,5,7) and a.store_id=#{storeId}

        and DATE_FORMAT(a.add_time,'%Y-%m-%d')=#{date}


        and DATE_FORMAT(a.add_time,'%Y-%m')=#{date}


        and p.mch_id=#{mchId}


        and p.mch_id!=#{mchId}

select
d.id,d.p_id,d.p_name, d.courier_num, d.express_id, d.num
from lkt_order_details as d
left join lkt_order as o on  d.r_sNo = o.sNo

    d.store_id = #{store_id}

        and o.sNo = #{sNo}


        and o.real_sno = #{Real_sno}


        and o.p_sNo = #{p_sNo}

SELECT d.r_status,o.real_sno,o.pay FROM lkt_order_details d
INNER JOIN lkt_order o ON o.sNo = d.r_sNo
where d.id = #{pId} and o.sNo = #{sNo} and d.store_id = #{storeId}

SELECT DISTINCT product_class
FROM (
         SELECT substring_index(substring_index(b.product_class, '-', 2), '-', -1) AS product_class
         FROM lkt_order_details AS a
                  RIGHT JOIN lkt_configure c ON a.sid = c.id
                  RIGHT JOIN lkt_product_list AS b ON c.pid = b.id
         WHERE b.store_id = #{storeId} AND a.user_id = #{userId}
         ORDER BY b.add_date DESC
     ) AS temp;
